mapper.select:
/* RcpSimpMgmtMapper.getRcpSimpRateList */ SELECT A.ADDITION_KEY AS additionKey , A.ADDITION_NAME AS additionName , A.ADDITION_CHECKED AS additionChecked , A.RANTAL AS rantal , A.GRP_NM AS grpNm FROM ( SELECT '1' AS SORT_ORD , A.ADDITION_KEY , B.ADDITION_NAME , '1' AS ADDITION_CHECKED , NVL(B.RANTAL, 0) AS RANTAL , B.CHARGE_FLAG , '프로모션할인' AS GRP_NM FROM VW_CHRG_PRMT_DTL A , MCP_ADDITION@DL_MCP B WHERE A.ADDITION_KEY = B.ADDITION_KEY AND A.USG_YN = 'Y' AND NVL(REPLACE(#{reqInDay}, '-', ''), TO_CHAR(SYSDATE, 'YYYYMMDD')) BETWEEN A.STRT_DT AND A.END_DT AND A.ORGN_ID = #{cntpntShopId} AND A.REQ_BUY_TYPE = #{reqBuyType} AND A.RATE_CD = #{rateCd} AND (CASE WHEN #{operType} = 'NAC3' THEN A.NAC_YN WHEN #{operType} = 'MNP3' THEN A.MNP_YN ELSE 'N' END) = 'Y' AND (CASE WHEN #{agrmTrm} = '0' THEN A.ENGG_CNT_0 WHEN #{agrmTrm} = '12' THEN A.ENGG_CNT_12 WHEN #{agrmTrm} = '18' THEN A.ENGG_CNT_18 WHEN #{agrmTrm} = '24' THEN A.ENGG_CNT_24 WHEN #{agrmTrm} = '30' THEN A.ENGG_CNT_30 WHEN #{agrmTrm} = '36' THEN A.ENGG_CNT_36 ELSE 'N' END) = 'Y'
AND A.ON_OFF_TYPE = #{onOffType}
UNION ALL SELECT '2' AS SORT_ORD , A.ADDITION_KEY , A.ADDITION_NAME , '1' AS ADDITION_CHECKED , NVL(A.RANTAL, 0) AS RANTAL , A.CHARGE_FLAG , B.CD_DSC AS GRP_NM FROM MCP_ADDITION@DL_MCP A , CMN_GRP_CD_MST B WHERE A.CHARGE_FLAG = B.CD_VAL AND B.GRP_ID = 'RCP9008' AND A.ACT_FLAG = 'Y' AND A.CHARGE_FLAG = 'F' UNION ALL SELECT '3' AS SORT_ORD , A.ADDITION_KEY , A.ADDITION_NAME , DECODE(C.ADDITION_KEY, NULL, '0', '1') AS ADDITION_CHECKED , NVL(A.RANTAL, 0) AS RANTAL , A.CHARGE_FLAG , D.CD_DSC AS GRP_NM FROM MCP_ADDITION@DL_MCP A , MSP_RATE_MST B , MCP_REQUEST_ADDITION@DL_MCP C , CMN_GRP_CD_MST D WHERE A.SOC = B.RATE_CD AND A.CHARGE_FLAG = D.CD_VAL AND D.GRP_ID = 'RCP9008' AND A.ACT_FLAG = 'Y' AND A.OSST_YN = 'Y' AND A.CHARGE_FLAG <> 'R' AND A.ADDITION_KEY = C.ADDITION_KEY(+) AND C.REQUEST_KEY(+) = #{requestKey} ) A ORDER BY A.SORT_ORD, A.CHARGE_FLAG, A.RANTAL, A.ADDITION_NAME

mapper.update:
		/* RcpSimpMgmtMapper.updMcpMovePayClaByInfo */
		UPDATE MCP_REQUEST_MOVE@DL_MCP
		SET
			OSST_PAY_DAY		= #{osstPayDay}
			, OSST_PAY_TYPE		= #{osstPayType}
 			, RVISN_ID 			= #{sessionUserId}
			, RVISN_DTTM 		= SYSDATE
		WHERE REQUEST_KEY = #{requestKey}

mapper.select:
/* RcpSimpMgmtMapper.getRcpSmsTemplateList */ SELECT A.TEMPLATE_ID , A.TEMPLATE_NM , A.CALLBACK , A.SUBJECT , A.TEXT , A.MSG_TYPE , A.EXPIRE_HOUR * 60 * 60 AS EXPIRE_TIME FROM MSP_SMS_TEMPLATE_MST A , CMN_GRP_CD_MST B WHERE A.TEMPLATE_ID = B.CD_VAL AND B.GRP_ID = 'RCP2043' AND B.USG_YN = 'Y'
AND INSTR(B.ETC1, #{operType}) > 0
ORDER BY A.TEMPLATE_ID

/* RcpSimpMgmtMapper.getRcpSmsSendList */ SELECT NVL(B.CD_DSC, '일반발송') AS TEMPLATE_NM , A.DSTADDR , A.CALLBACK , TO_CHAR(A.REQUEST_TIME, 'YYYYMMDDHH24MISS') AS REQUEST_TIME , TO_CHAR(A.SEND_TIME, 'YYYYMMDDHH24MISS') AS SEND_TIME , A.TEXT , A.SUBJECT , A.EXPIRETIME AS EXPIRE_TIME , A.MSG_TYPE , A.OPT_ID AS TEMPLATE_ID , A.EXT_COL0 AS RES_NO , C.CD_DSC AS RESULT_NM FROM MSG_RESULT A , CMN_GRP_CD_MST B , CMN_GRP_CD_MST C WHERE A.OPT_ID = B.CD_VAL(+) AND B.GRP_ID(+) = 'RCP2043' AND TRIM(A.RESULT) = C.CD_VAL AND C.GRP_ID = 'CMN0068' AND TRUNC(A.REQUEST_TIME) BETWEEN TRUNC(TO_DATE(#{searchStartDt}, 'YYYYMMDD')) AND TRUNC(TO_DATE(#{searchEndDt}, 'YYYYMMDD'))
AND A.DSTADDR = #{searchVal}
AND A.EXT_COL0 = #{searchVal}
ORDER BY A.REQUEST_TIME DESC

/* RcpSimpMgmtMapper.getRcpSmsSendListOld */ SELECT NVL(B.CD_DSC, '일반발송') AS TEMPLATE_NM , A.DSTADDR , A.CALLBACK , TO_CHAR(A.REQUEST_TIME, 'YYYYMMDDHH24MISS') AS REQUEST_TIME , TO_CHAR(A.SEND_TIME, 'YYYYMMDDHH24MISS') AS SEND_TIME , A.TEXT , A.SUBJECT , A.EXPIRETIME AS EXPIRE_TIME , A.MSG_TYPE , A.OPT_ID AS TEMPLATE_ID , A.EXT_COL0 AS RES_NO , C.CD_DSC AS RESULT_NM FROM MSG_RESULT_20190521 A , CMN_GRP_CD_MST B , CMN_GRP_CD_MST C WHERE A.OPT_ID = B.CD_VAL(+) AND B.GRP_ID(+) = 'RCP2043' AND TRIM(A.RESULT) = C.CD_VAL AND C.GRP_ID = 'CMN0068' AND TRUNC(A.REQUEST_TIME) BETWEEN TRUNC(TO_DATE(#{searchStartDt}, 'YYYYMMDD')) AND TRUNC(TO_DATE(#{searchEndDt}, 'YYYYMMDD'))
AND A.DSTADDR = #{searchVal}
AND A.EXT_COL0 = #{searchVal}
ORDER BY A.REQUEST_TIME DESC
